data.script:
const STEP = 30;
const MIN_X = -380, MAX_X = 380;
const MIN_Y = -280, MAX_Y = 280;

if (!state.best_y) state.best_y = 250;

let moved = false;
if (Input.isKeyPressed('ArrowUp')) {
  self.y -= STEP;
  moved = true;
}
if (Input.isKeyPressed('ArrowDown')) {
  self.y += STEP;
  moved = true;
}
if (Input.isKeyPressed('ArrowLeft')) {
  self.x -= STEP;
  moved = true;
}
if (Input.isKeyPressed('ArrowRight')) {
  self.x += STEP;
  moved = true;
}

if (moved) {
  self.x = Math.max(MIN_X, Math.min(MAX_X, self.x));
  self.y = Math.max(MIN_Y, Math.min(MAX_Y, self.y));
  if (self.y < state.best_y) state.best_y = self.y;
}

// Check win condition (reached top)
if (self.y <= -260) {
  console.log('WIN!');
  self.x = 0;
  self.y = 250;
  state.best_y = 250;
}

template.script:
const SPEED = 100;
const WRAP_LEFT = -420, WRAP_RIGHT = 420;
const PLAYER_HW = 12, PLAYER_HH = 12;
const CAR_HW = 25, CAR_HH = 10;

// Move left
self.x -= SPEED * dt;

// Wrap around
if (self.x < WRAP_LEFT) self.x = WRAP_RIGHT;

// Collision with player
let player = entities.get('Player');
if (player) {
  let dx = Math.abs(self.x - player.x);
  let dy = Math.abs(self.y - player.y);
  if (dx < CAR_HW + PLAYER_HW && dy < CAR_HH + PLAYER_HH) {
    player.x = 0;
    player.y = 250;
    state.best_y = 250;
    console.log('HIT! Reset to start');
  }
}

